import { Component, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { trigger, transition, style, animate } from '@angular/animations';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { ParkaddaService } from '../../../../services/parkadda.service';
import { ParkaddaAuthService } from '../../../../services/parkadda-auth.service';
import { ParkingLocation, ParkingOccupancy } from '../../../../models/parkadda.models';

@Component({
  selector: 'app-analytics-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './analytics-dashboard.component.html',
  styleUrls: ['./analytics-dashboard.component.scss'],
  animations: [
    trigger('fadeInOut', [
      transition(':enter', [
        style({ opacity: 0, transform: 'translateY(-10px)' }),
        animate('300ms ease-in', style({ opacity: 1, transform: 'translateY(0)' }))
      ])
    ])
  ]
})
export class AnalyticsDashboardComponent implements OnInit, OnDestroy {
  selectedParking: ParkingLocation | null = null;
  occupancyData: ParkingOccupancy | null = null;
  loading = false;
  error: string | null = null;
  dateFrom = this.getDefaultFromDate();
  dateTo = this.getDefaultToDate();
  selectedMetric = 'occupancy';

  // Dashboard metrics
  totalVehicles = 0;
  totalTransactions = 0;
  totalRevenue = 0;
  vehicleInCount = 0;
  vehicleOutCount = 0;
  averageOccupancy = 0;
  peakHour = '';

  vehicleChartData: any = null;
  transactionChartData: any = null;
  occupancyChartData: any = null;

  private destroy$ = new Subject<void>();

  constructor(
    private parkaddaService: ParkaddaService,
    private authService: ParkaddaAuthService,
    private route: ActivatedRoute
  ) {}

  ngOnInit(): void {
    // Initialize with first parking location from service
    this.loadDashboardData();

    if (!this.selectedParking) {
      this.error = 'Please select a parking location first';
      return;
    }

    this.route.queryParams.pipe(takeUntil(this.destroy$)).subscribe(params => {
      if (params['from_date']) {
        this.dateFrom = params['from_date'];
      }
      if (params['to_date']) {
        this.dateTo = params['to_date'];
      }
      this.loadDashboardData();
    });
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadDashboardData(): void {
    if (!this.selectedParking) return;

    this.loading = true;
    this.error = null;

    // Load occupancy data
    this.parkaddaService
      .getParkingOccupancy(this.selectedParking.parking_table_id)
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (data) => {
          this.occupancyData = data;
          this.averageOccupancy = data.occupancy_percentage || 0;
        },
        error: (err) => console.error('Error loading occupancy:', err)
      });

    // Load vehicle reports
    this.loadVehicleReports();

    // Load transaction reports
    this.loadTransactionReports();
  }

  loadVehicleReports(): void {
    if (!this.selectedParking) return;

    const params = {
      page: 1,
      page_size: 1,
      parking_table_id: this.selectedParking.parking_table_id,
      from_date_filter: this.dateFrom,
      to_date_filter: this.dateTo
    };

    this.parkaddaService
      .searchAdminVehicleInReports(params)
      .pipe(takeUntil(this.destroy$))
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          this.vehicleInCount = response.data?.results?.length || 0;
          this.totalVehicles += this.vehicleInCount;
        },
        error: (err: any) => console.error('Error loading vehicle in reports:', err)
      });

    this.parkaddaService
      .searchAdminVehicleOutReports(params)
      .pipe(takeUntil(this.destroy$))
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          this.vehicleOutCount = response.data?.results?.length || 0;
          this.totalVehicles += this.vehicleOutCount;
        },
        error: (err: any) => console.error('Error loading vehicle out reports:', err)
      });
  }

  loadTransactionReports(): void {
    if (!this.selectedParking) return;

    const params = {
      page: 1,
      page_size: 1,
      parking_table_id: this.selectedParking.parking_table_id,
      from_date_filter: this.dateFrom,
      to_date_filter: this.dateTo
    };

    // Load cash transactions
    this.parkaddaService
      .getCashTransactions(params)
      .pipe(takeUntil(this.destroy$))
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          this.totalTransactions += response.data?.results?.length || 0;
          this.totalRevenue += this.calculateRevenue(response.data);
        },
        error: (err: any) => console.error('Error loading cash transactions:', err)
      });

    // Load card transactions
    this.parkaddaService
      .getCardTransactions(params)
      .pipe(takeUntil(this.destroy$))
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          this.totalTransactions += response.data?.results?.length || 0;
          this.totalRevenue += this.calculateRevenue(response.data);
        },
        error: (err: any) => console.error('Error loading card transactions:', err)
      });

    // Load UPI transactions
    this.parkaddaService
      .getUPITransactions(params)
      .pipe(takeUntil(this.destroy$))
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          this.totalTransactions += response.data?.results?.length || 0;
          this.totalRevenue += this.calculateRevenue(response.data);
        },
        error: (err: any) => console.error('Error loading UPI transactions:', err),
        complete: () => { this.loading = false; }
      });
  }

  calculateRevenue(data: any): number {
    if (!data.results) return 0;
    return data.results.reduce((sum: number, item: any) => {
      return sum + (item.amount || item.transaction_amount || 0);
    }, 0);
  }

  onDateRangeChange(): void {
    this.loadDashboardData();
  }

  getOccupancyStatus(): string {
    if (this.averageOccupancy < 30) return 'Low';
    if (this.averageOccupancy < 70) return 'Medium';
    return 'High';
  }

  getOccupancyStatusClass(): string {
    if (this.averageOccupancy < 30) return 'status-low';
    if (this.averageOccupancy < 70) return 'status-medium';
    return 'status-high';
  }

  refreshData(): void {
    this.loadDashboardData();
  }

  private getDefaultFromDate(): string {
    const date = new Date();
    date.setDate(date.getDate() - 30);
    return date.toISOString().split('T')[0];
  }

  private getDefaultToDate(): string {
    return new Date().toISOString().split('T')[0];
  }
}
